import json
from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify

app = Flask(__name__)

# Secure Elasticsearch client configuration
es = Elasticsearch(
    ['localhost:9200'],
    timeout=30,
    max_retries=3,
    retry_on_timeout=True
)

# Whitelist of allowed script languages (Painless is the secure default)
ALLOWED_LANGUAGES = ['painless']

# Whitelist of allowed aggregation types
ALLOWED_AGGREGATIONS = [
    'avg', 'sum', 'min', 'max', 'stats', 'extended_stats',
    'value_count', 'cardinality', 'percentiles', 'percentile_ranks'
]

# Predefined safe script templates
SAFE_SCRIPT_TEMPLATES = {
    'field_multiply': {
        'source': "doc[params.field].value * params.multiplier",
        'params': ['field', 'multiplier']
    },
    'field_sum': {
        'source': "doc[params.field1].value + doc[params.field2].value",
        'params': ['field1', 'field2']
    },
    'field_ratio': {
        'source': "doc[params.numerator].value / doc[params.denominator].value",
        'params': ['numerator', 'denominator']
    },
    'conditional_value': {
        'source': "doc[params.field].value > params.threshold ? params.high_value : params.low_value",
        'params': ['field', 'threshold', 'high_value', 'low_value']
    }
}

def validate_script_params(params):
    """Validate script parameters to prevent injection"""
    if not isinstance(params, dict):
        return False
    
    for key, value in params.items():
        # Only allow alphanumeric keys
        if not key.replace('_', '').isalnum():
            return False
        
        # Only allow safe value types
        if not isinstance(value, (str, int, float, bool)):
            return False
        
        # Validate string values don't contain script injection attempts
        if isinstance(value, str):
            dangerous_patterns = [';', 'Runtime', 'Class', 'System', 'Process', 'exec', 'eval']
            if any(pattern in value for pattern in dangerous_patterns):
                return False
    
    return True

def validate_index_name(index_name):
    """Validate index name to prevent path traversal"""
    if not index_name:
        return False
    
    # Only allow alphanumeric, hyphens, underscores, and wildcards
    allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_*')
    if not all(c in allowed_chars for c in index_name):
        return False
    
    # Prevent path traversal
    if '..' in index_name or '/' in index_name:
        return False
    
    return True

def build_secure_aggregation(agg_config):
    """Build aggregation query with security controls"""
    agg_type = agg_config.get('type')
    
    if agg_type not in ALLOWED_AGGREGATIONS:
        raise ValueError(f"Aggregation type '{agg_type}' not allowed")
    
    script_template = agg_config.get('script_template')
    
    if not script_template or script_template not in SAFE_SCRIPT_TEMPLATES:
        raise ValueError("Invalid or missing script template")
    
    params = agg_config.get('params', {})
    
    if not validate_script_params(params):
        raise ValueError("Invalid script parameters")
    
    template = SAFE_SCRIPT_TEMPLATES[script_template]
    
    # Verify all required parameters are provided
    for required_param in template['params']:
        if required_param not in params:
            raise ValueError(f"Missing required parameter: {required_param}")
    
    # Build the aggregation with stored script template
    aggregation = {
        agg_type: {
            'script': {
                'lang': 'painless',
                'source': template['source'],
                'params': params
            }
        }
    }
    
    return aggregation

@app.route('/api/aggregate', methods=['POST'])
def execute_aggregation():
    """Execute aggregation with secure script handling"""
    try:
        req_data = request.get_json()
        
        if not req_data:
            return jsonify({'error': 'Invalid request data'}), 400
        
        # Validate index name
        index_name = req_data.get('index')
        if not validate_index_name(index_name):
            return jsonify({'error': 'Invalid index name'}), 400
        
        # Validate aggregation configuration
        agg_config = req_data.get('aggregation')
        if not agg_config:
            return jsonify({'error': 'Missing aggregation configuration'}), 400
        
        # Build secure aggregation
        aggregation = build_secure_aggregation(agg_config)
        
        # Optional query filter
        query = req_data.get('query', {'match_all': {}})
        
        # Execute search with aggregation
        response = es.search(
            index=index_name,
            body={
                'size': 0,
                'query': query,
                'aggs': {
                    'result': aggregation
                }
            }
        )
        
        return jsonify({
            'success': True,
            'aggregations': response.get('aggregations', {})
        })
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/api/templates', methods=['GET'])
def list_templates():
    """List available script templates"""
    templates = {}
    for name, template in SAFE_SCRIPT_TEMPLATES.items():
        templates[name] = {
            'description': template['source'],
            'required_params': template['params']
        }
    return jsonify({'templates': templates})

@app.route('/health', methods=['GET'])
def health_check():
    """Health check endpoint"""
    try:
        es.cluster.health()
        return jsonify({'status': 'healthy'})
    except Exception:
        return jsonify({'status': 'unhealthy'}), 503

